  connectionString: process.env.DATABASE_URL,
  max: 10,                       // hovuzdagi ulanishlar soni
  idleTimeoutMillis: 30_000,     // bo'sh ulanish 30s dan keyin yopiladi
  connectionTimeoutMillis: 5_000 // ulanish kutish chegarasi
});

