import { createClient } from 'redis';

const redis = createClient({ url: process.env.REDIS_URL });
await redis.connect();

// Umumiy cache-aside helper: kesh -> manba -> keshga yozish (TTL bilan)
async function cacheAside<T>(
  key: string,
  ttlSec: number,
  load: () => Promise<T>,
): Promise<T> {
  const hit = await redis.get(key);
  if (hit) return JSON.parse(hit) as T; // cache hit - DB'ga tegmaymiz

  const fresh = await load(); // cache miss - manbadan o'qiymiz
  await redis.set(key, JSON.stringify(fresh), { EX: ttlSec });
  return fresh;
}

const product = await cacheAside(`product:${id}`, 120, () =>
