);

// Yozishda invalidatsiya: eski keshni o'chir - keyingi o'qish yangisini keshlaydi
async function updateProduct(id: string, patch: Record<string, unknown>) {
  const updated = await db.product.update(id, patch);
  await redis.del(`product:${id}`);
  return updated;
