// WRITE-THROUGH: keshga va DB'ga birga yoziladi - kesh doim yangi.
async function writeThrough(id: string, value: Product) {
  await db.product.update(id, value);                 // 1) DB
  await redis.set(`product:${id}`, JSON.stringify(value), { EX: 300 }); // 2) kesh
  return value;
}

// WRITE-BEHIND: avval keshga (tez), DB'ga keyin fonda (batch).
// Xavf: kesh yiqilsa, hali DB'ga o'tmagan yozuv yo'qoladi.
async function writeBehind(id: string, value: Product) {
  await redis.set(`product:${id}`, JSON.stringify(value), { EX: 300 });
  await redis.rPush('dirty:products', id); // navbatga qo'y
  return value; // DB'ga yozishni kutmaymiz - javob tez
}

// Fon ishchisi navbatni vaqti-vaqti bilan DB'ga oqizadi (flush).
async function flushDirty() {
  const ids = await redis.lRange('dirty:products', 0, -1);
  for (const id of ids) {
    const raw = await redis.get(`product:${id}`);
    if (raw) await db.product.update(id, JSON.parse(raw));
  }
  await redis.del('dirty:products');
}

// TTL'ga jitter qo'shamiz - kalitlar bir vaqtda tugamaydi.
const withJitter = (base: number) => base + Math.floor(Math.random() * 30);

async function getWithLock<T>(key: string, ttl: number, load: () => Promise<T>): Promise<T> {
  const hit = await redis.get(key);
  if (hit) return JSON.parse(hit) as T; // cache hit

  const lockKey = `lock:${key}`;
  // SET NX: faqat lock yo'q bo'lsa qo'yadi. Bittasi lock oladi.
  const gotLock = await redis.set(lockKey, '1', { NX: true, PX: 5000 });

  if (!gotLock) {
    // Lock band - boshqa so'rov hisoblayapti. Biroz kutib, keshdan qayta o'qiymiz.
    await new Promise((r) => setTimeout(r, 50));
    const retry = await redis.get(key);
    if (retry) return JSON.parse(retry) as T;
    return load(); // eng yomon holatda o'zimiz hisoblaymiz
  }

  try {
    const fresh = await load(); // faqat lock egasi DB'ga uriladi
    await redis.set(key, JSON.stringify(fresh), { EX: withJitter(ttl) });
    return fresh;
  } finally {
    await redis.del(lockKey); // lock'ni bo'shat
  }
}

